                value={snippetForm.snippet}
                onChange={v => setSnippetForm(prev => ({ ...prev, snippet: v }))}
                placeholder="Enter your snippet content..."
                rows={5}
              />
              <FormCheckbox
                label="Share with team"
                checked={snippetForm.isShared}
                onChange={v => setSnippetForm(prev => ({ ...prev, isShared: v }))}
                description="Make this snippet available to your team members"
              />
              <FormDatePicker
                label="Expires"
                value={snippetForm.expiresAt}
                onChange={v => setSnippetForm(prev => ({ ...prev, expiresAt: v }))}
                description="Optional expiration date"
              />
            </Form>
          ) : viewMode === 'grid' ? (
            filteredColors.length === 0 ? (
              <EmptyState
                icon={<SearchIcon />}
                title="No Colors"
                description="Try a different search term"
              />
            ) : (
              <Grid
                itemCount={filteredColors.length}
                columns={4}
                onActiveIndexChange={handleActiveIndexChange}
                onAction={handleGridAction}
              >
                {filteredColors.map((color, index) => (
                  <GridItem
                    key={color.id}
                    index={index}
                    icon={<ColorSwatch color={color.color} />}
                    title={color.title}
                    subtitle={color.subtitle}
                  />
                ))}
              </Grid>
            )
          ) : allItems.length === 0 ? (
            <EmptyState
              icon={<SearchIcon />}
              title="No Results"
              description="Try a different search term"
            />
          ) : (
            <List
              itemCount={allItems.length}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleDrillIn}
            >
              {(() => {
                let globalIndex = 0;
                return filtered.map(section => (
                  <ListSection key={section.title} title={section.title}>
                    {section.items.map(item => {
                      const idx = globalIndex++;
                      return (
                        <ListItem
                          key={item.id}
                          index={idx}
                          title={item.title}
                          subtitle={item.subtitle}
                          icon={item.icon}
                          accessories={item.accessories}
                        />
                      );
                    })}
                  </ListSection>
                ));
              })()}
            </List>
          )}
        </div>
        {detail && (
          <Detail
            markdown={detail.markdown}
            metadata={
              detail.metadata ? (
                <DetailMetadata>
                  {detail.metadata.map(renderMetadataEntry)}
                </DetailMetadata>
              ) : undefined
            }
          />
        )}
      </div>
      <ActionPanel
        actions={
          viewMode === 'form'
            ? [
                {
                  label: 'Submit',
                  shortcut: (
                    <Kbd
                      keys={[
                        '⌘',
                        '↵',
                      ]}
                    />
                  ),
                  onClick: handleSubmitSnippet,
                },
              ]
            : [
                {
                  label: 'Open',
                  shortcut: <Kbd keys={['↵']} />,
                },
                {
                  label: 'Actions',
                  shortcut: (
                    <Kbd
                      keys={[
                        '⌘',
                        'K',
                      ]}
                    />
                  ),
                  onClick: toggleActions,
                },
              ]
        }
        dropdownOpen={actionsOpen}
        dropdownActions={dropdownActions}
        onDropdownClose={closeActions}
      />
      <ToastContainer toasts={toasts} onDismiss={hideToast} />
    </CommandPalette>
  );
}

