import { useId } from 'react';

interface FormCheckboxProps {
  label: string;
  checked: boolean;
  onChange: (checked: boolean) => void;
  description?: string;
}

export function FormCheckbox({
  label,
  checked,
  onChange,
  description,
}: FormCheckboxProps) {
  const id = useId();

  return (
    <div className="form-checkbox">
      <div className="form-checkbox__row">
        <div
          className={`form-checkbox__box${checked ? ' form-checkbox__box--checked' : ''}`}
          role="checkbox"
          aria-checked={checked}
          tabIndex={0}
          id={id}
          onClick={() => onChange(!checked)}
          onKeyDown={e => {
            if (e.key === ' ' || e.key === 'Enter') {
              e.preventDefault();
              onChange(!checked);
            }
          }}
        >
          {checked && (
            <svg
              width="10"
              height="10"
              viewBox="0 0 10 10"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                d="M2 5L4.5 7.5L8 2.5"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          )}
        </div>
        <label className="form-checkbox__label" htmlFor={id}>
          {label}
        </label>
      </div>
      {description && (
        <span className="form-checkbox__description">{description}</span>
      )}
    </div>
  );
}

