  return (
    <FormField
      label={label}
      description={description}
      error={error}
      htmlFor={id}
    >
      <input
        id={id}
        className="form-input form-input--date"
        type={includeTime ? 'datetime-local' : 'date'}
        value={value}
        onChange={e => onChange(e.target.value)}
        min={min}
        max={max}
      />
    </FormField>
  );
