import './form.scss';

interface FormProps {
  children: ReactNode;
  onSubmit?: () => void;
}

export function Form({ children, onSubmit }: FormProps) {
  function handleSubmit(e: FormEvent) {
    e.preventDefault();
    onSubmit?.();
  }

  return (
    <form className="form" onSubmit={handleSubmit} noValidate>
      <div className="form__fields">{children}</div>
    </form>
  );
}

